// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	var inTitle bool

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			err = z.Err()
			if err == io.EOF {
				err = nil // End of document, not an error
			}
			return
		case html.StartTagToken:
			tag, hasAttr := z.TagName()
			tagStr := strings.ToLower(string(tag))
			if tagStr == "title" {
				inTitle = true
			} else if tagStr == "meta" {
				var name, content string
				for hasAttr {
					var key, val []byte
					key, val, hasAttr = z.TagAttr()
					keyStr := strings.ToLower(string(key))
					valStr := string(val)
					valStr = strings.Trim(valStr, `"'`)
					if keyStr == "name" {
						name = valStr
					} else if keyStr == "content" {
						content = valStr
					}
				}
				if strings.ToLower(name) == "description" {
					description = content
					if title != "" && description != "" {
						return
					}
				}
			}
		case html.EndTagToken:
			tag, _ := z.TagName()
			tagStr := strings.ToLower(string(tag))
			if tagStr == "title" {
				inTitle = false
			}
		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(string(z.Text()))
				if title != "" && description != "" {
					return
				}
			}
		}
	}
}

