// isIPPrivate checks if an IP address is in a private or loopback range.
func isIPPrivate(ip net.IP) bool {
	// IPv4 private ranges
	if ip.To4() != nil {
		return ip.IsLoopback() ||
			ip[0] == 10 ||                      // 10.0.0.0/8
			(ip[0] == 172 && (ip[1] >= 16 && ip[1] <= 31)) || // 172.16.0.0/12
			(ip[0] == 192 && ip[1] == 168) // 192.168.0.0/16
	}
	// IPv6 private ranges
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() ||
		ip.IsInterfaceLocalMulticast() || strings.HasPrefix(ip.String(), "fd") // Unique Local Addresses (fd00::/8)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

