					ctx.Error("Invalid redirect URL format", fasthttp.StatusBadGateway)
					return
				}

				if parsedRedirectURL.Scheme != "http" && parsedRedirectURL.Scheme != "https" {
					ctx.Error("Redirect URL must use http or https scheme", fasthttp.StatusForbidden)
					return
				}

				// Check if redirect host resolves to private IP
				redirectHost := parsedRedirectURL.Hostname()
				redirectIPs, err := net.LookupIP(redirectHost)
				if err != nil {
					ctx.Error("Failed to resolve redirect host", fasthttp.StatusBadGateway)
					return
				}
				for _, ip := range redirectIPs {
					if isIPPrivate(ip) {
