						return
					}
				}

				// Proceed to follow redirect
				currentURL = resolvedLocation
			} else {
				// No more redirects, check status code
				if res.StatusCode() != fasthttp.StatusOK {
					ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
					return
				}
				break // Exit loop if no redirect
			}
