	}

	// Parse the URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid URL: " + err.Error()})
		return
	}

	// Check valid scheme (http/https only)
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid scheme: only http/https are allowed"})
