	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponsePayload{
			URL:   payload.URL,
			Error: fmt.Sprintf("Unexpected status code: %d", resp.StatusCode()),
