// isBlockedIP checks if an IP address is in a blocked range (private, loopback, etc.)
func isBlockedIP(ip net.IP) bool {
	// Block loopback addresses
	if ip.IsLoopback() {
		return true
	}
	// Block private IPv4 ranges
	privateIPv4Ranges := []*net.IPNet{
		{IP: net.IPv4(10, 0, 0, 0), Mask: net.CIDRMask(8, 32)},    // 10.0.0.0/8
		{IP: net.IPv4(172, 16, 0, 0), Mask: net.CIDRMask(12, 32)},  // 172.16.0.0/12
		{IP: net.IPv4(192, 168, 0, 0), Mask: net.CIDRMask(16, 32)}, // 192.168.0.0/16
	}
	for _, r := range privateIPv4Ranges {
		if r.Contains(ip) {
			return true
		}
	}
	// Block private IPv6 ranges (unique local addresses)
	privateIPv6Ranges := []*net.IPNet{
		{IP: net.ParseIP("fd00::"), Mask: net.CIDRMask(8, 128)}, // fd00::/8
	}
	for _, r := range privateIPv6Ranges {
		if r.Contains(ip) {
			return true
		}
	}
	return false
}

