func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Invalid request body"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "URL is required"})
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	var resp fasthttp.Response
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")

	ctxTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	errChan := make(chan error, 1)
	go func() {
		errChan <- client.DoRedirects(req, &resp, 10)
		close(errChan)
	}()

	select {
	case err := <-errChan:
		if err != nil {
			ctx.SetStatusCode(fasthttp.StatusInternalServerError)
			ctx.Response.Header.SetContentType("application/json")
			json.NewEncoder(ctx).Encode(map[string]string{"error": "Failed to fetch URL: " + err.Error()})
			return
		}
	case <-ctxTimeout.Done():
		ctx.SetStatusCode(fasthttp.StatusGatewayTimeout)
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Request timeout"})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "URL returned status code " + string(rune(resp.StatusCode()))})
		return
	}

	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(resp.Body()))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Response.Header.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Failed to parse HTML: " + err.Error()})
		return
	}

	title := doc.Find("title").Text()
	description := doc.Find("meta[name='description']").AttrOr("content", "")

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Response.Header.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(ResponseBody{
		Title:       title,
		Description: description,
	})
}

