// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = strings.TrimSpace(n.FirstChild.Data)
		}

		// Extract meta description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = strings.ToLower(attr.Val)
				} else if attr.Key == "content" {
					content = attr.Val
				} else if attr.Key == "property" && strings.ToLower(attr.Val) == "og:description" {
					// Also check for OpenGraph description
					content = attr.Val
					name = "description" // Treat og:description as description
				}
			}

			if name == "description" && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return
