// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL scheme
		parsedURL, err := url.ParseRequestURI(targetURL)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Resolve hostname to IP addresses and check for private/loopback IPs
		ips, err := net.LookupIP(parsedURL.Hostname())
		if err != nil {
			ctx.Error("Failed to resolve hostname", fasthttp.StatusBadRequest)
			return
		}
		for _, ip := range ips {
			if isPrivateIP(ip) {
				ctx.Error("URL is not accessible (internal IP)", fasthttp.StatusBadRequest)
				return
			}
		}

		// Use fasthttp.Client to fetch with timeout and limits
		client := &fasthttp.Client{
			Dial:                fasthttp.DialDualStack,
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 10 * time.Second,
			MaxConnsPerHost:     10,
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 10
		if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		if res.StatusCode() != fasthttp.StatusOK {
			ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
			return
		}

		const maxResponseSize = 1 << 20 // 1MB
		contentLength := res.Header.ContentLength()
		if contentLength > maxResponseSize {
			ctx.Error("Response too large", fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		// Limit body size even if Content-Length is not present
		if len(bodyBytes) > maxResponseSize {
			ctx.Error("Response too large", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Extract title
	var extractTitle func(*html.Node)
	extractTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = strings.TrimSpace(n.FirstChild.Data)
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractTitle(c)
			if title != "" {
				return // Stop after first title
			}
		}
	}
	extractTitle(doc)

	// Extract meta description
	var extractMetaDescription func(*html.Node)
	extractMetaDescription = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var hasName, hasContent bool
			var content string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
					hasName = true
				}
				if strings.EqualFold(attr.Key, "content") {
					hasContent = true
					content = attr.Val
				}
			}
			if hasName && hasContent {
				description = strings.TrimSpace(content)
				return
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractMetaDescription(c)
			if description != "" {
				return // Stop after first meta description
			}
		}
	}
	extractMetaDescription(doc)

	return
}

// isPrivateIP checks if an IP address is private or loopback.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsPrivate() { // IsPrivate is available in Go 1.17+
		return true
	}

	// Check IPv4 private ranges
	privateIPv4Ranges := []*net.IPNet{
		{IP: net.IPv4(10, 0, 0, 0), Mask: net.CIDRMask(8, 32)},
		{IP: net.IPv4(172, 16, 0, 0), Mask: net.CIDRMask(12, 32)},
		{IP: net.IPv4(192, 168, 0, 0), Mask: net.CIDRMask(16, 32)},
	}
	for _, r := range privateIPv4Ranges {
		if r.Contains(ip) {
			return true
		}
	}

	// Check IPv6 link-local or unique local
	if ip.To4() == nil { // IPv6
		if strings.HasPrefix(ip.String(), "fe80:") { // Link-local
			return true
		}
		if strings.HasPrefix(ip.String(), "fd00:") { // Unique local
			return true
		}
	}

	return false
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

