	if host == "localhost" || host == "0.0.0.0" || host == "::1" {
		respBody := ResponseBody{Error: "URL points to a local address, which is not allowed"}
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, respBody)
		return
