		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
		// IPv6 loopback
		{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
		// IPv6 private ranges (ULA)
		{IP: net.ParseIP("fd00::"), Mask: net.CIDRMask(8, 128)},
	}

	// Check if any resolved IP is in a blocked range
	for _, ip := range ips {
		for _, r := range privateIPRanges {
			if r.Contains(ip) {
				respBody := ResponseBody{Error: "URL points to a private network address, which is not allowed"}
				sendJSONResponse(ctx, fasthttp.StatusBadRequest, respBody)
				return
			}
		}
	}

	// Configure fasthttp client with timeout
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		MaxIdleConnDuration: 3 * time.Second,
	}

	// Create context with 3-second timeout
	ctxWithTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")

	// Perform request with redirect following
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)
	err = client.DoRedirects(req, resp, 10)
	if err != nil {
		// Check if it was a timeout
		if ctxWithTimeout.Err() == context.DeadlineExceeded {
			respBody := ResponseBody{Error: "Request timed out"}
			sendJSONResponse(ctx, fasthttp.StatusGatewayTimeout, respBody)
		} else {
