			sendJSONResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		}
		return
	}

	// Check if we received an HTML response
	contentType := string(resp.Header.ContentType())
	if !bytes.Contains(bytes.ToLower([]byte(contentType)), []byte("text/html")) {
		respBody := ResponseBody{Error: "Response is not HTML"}
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, respBody)
		return
	}

	// Parse HTML to extract title and description
	doc, err := html.Parse(bytes.NewReader(resp.Body()))
	if err != nil {
		respBody := ResponseBody{Error: "Failed to parse HTML: " + err.Error()}
		sendJSONResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		return
	}

	// Extract information from HTML
	var title, description string
	var extract func(*html.Node)
	extract = func(n *html.Node) {
		// Extract title
		if n.Type == html.ElementNode && n.DataAtom == atom.Title && title == "" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = n.FirstChild.Data
			}
		}

		// Extract meta description
		if n.Type == html.ElementNode && n.DataAtom == atom.Meta && description == "" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" {
					name = attr.Val
				} else if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name == "description" {
				description = content
			}
		}

		// Recursively visit all children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extract(c)
		}
	}
	extract(doc)

	// Send response
	respBody := ResponseBody{
		Title:       title,
		Description: description,
	}
	sendJSONResponse(ctx, fasthttp.StatusOK, respBody)
}

// sendJSONResponse sends a JSON response with the specified status code
func sendJSONResponse(ctx *fasthttp.RequestCtx, statusCode int, data interface{}) {
	ctx.SetStatusCode(statusCode)
	jsonData, err := json.Marshal(data)
	if err != nil {
		log.Printf("Failed to marshal response: %v", err)
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.WriteString(`{"error":"Failed to marshal response"}`)
		return
	}
