		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil
			}
			return
		case html.StartTagToken, html.SelfClosingTagToken:
			tag, hasAttr := tokenizer.TagName()
			tagStr := strings.ToLower(string(tag))

			if tagStr == "title" {
				tt = tokenizer.Next()
				if tt == html.TextToken {
					title = strings.TrimSpace(string(tokenizer.Text()))
				}
			} else if tagStr == "meta" {
				var key, val []byte
				contentVal := ""
				isDesc := false
				for hasAttr {
					key, val, hasAttr = tokenizer.TagAttr()
					keyStr := strings.ToLower(string(key))
					valStr := string(val)
					if (keyStr == "name" && strings.ToLower(valStr) == "description") ||
						(keyStr == "property" && strings.ToLower(valStr) == "og:description") {
						isDesc = true
					}
					if keyStr == "content" {
						contentVal = strings.TrimSpace(valStr)
					}
				}
				if isDesc && contentVal != "" && description == "" {
					description = contentVal
				}
			}
		}

		// Early return if both title and description are found
		if title != "" && description != "" {
			return
		}
	}
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

