// IsPrivateIP checks if an IP address is in a private network range
func IsPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// IPv4 private ranges
	privateIPv4Ranges := []*net.IPNet{
		{IP: net.IPv4(10, 0, 0, 0), Mask: net.CIDRMask(8, 32)},   // 10.0.0.0/8
		{IP: net.IPv4(172, 16, 0, 0), Mask: net.CIDRMask(12, 32)}, // 172.16.0.0/12
		{IP: net.IPv4(192, 168, 0, 0), Mask: net.CIDRMask(16, 32)}, // 192.168.0.0/16
		{IP: net.IPv4(169, 254, 0, 0), Mask: net.CIDRMask(16, 32)}, // 169.254.0.0/16
	}
	for _, r := range privateIPv4Ranges {
		if r.Contains(ip) {
			return true
		}
	}
	// IPv6 private ranges
	privateIPv6Ranges := []*net.IPNet{
		{IP: net.IPv6loopback, Mask: net.CIDRMask(128, 128)}, // ::1/128
		{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)}, // fc00::/7 (unique local)
		{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)}, // fe80::/10 (link local)
	}
	for _, r := range privateIPv6Ranges {
		if r.Contains(ip) {
			return true
		}
	}
	return false
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type to JSON
	ctx.Response.Header.SetContentType("application/json")

	// Parse incoming JSON request
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Failed to parse request body: " + err.Error()})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "URL field is required"})
		return
	}

	// Initialize fasthttp client with required configurations
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request to fetch target URL
	reqURI := fasthttp.AcquireURI()
	defer fasthttp.ReleaseURI(reqURI)

	if err := reqURI.Parse(nil, []byte(req.URL)); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Invalid URL: " + err.Error()})
