	proto := string(reqURI.Scheme())
	if proto != "http" && proto != "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Invalid protocol: only http/https allowed"})
		return
