	var src fasthttp.Request
	src.SetRequestURI(req.URL)
	src.Header.SetMethod(fasthttp.MethodGet)

	// Fetch URL with following redirects
	const maxRedirects = 10
	if err := client.DoRedirects(&src, &dst, maxRedirects); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	// Check if response is HTML
	contentType := string(dst.Header.ContentType())
	if contentType == "" || !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Response is not HTML"})
		return
	}

	// Parse HTML to extract title and meta description
