	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{Error: "Failed to parse HTML: " + err.Error()})
		return
	}

	title := doc.Find("title").Text()

	description := ""
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		if name, exists := s.Attr("name"); exists && strings.ToLower(name) == "description" {
