func isDisallowedHost(host string) bool {
	// Remove port if present
	host = strings.Split(host, ":")[0]
	ip := net.ParseIP(host)
	if ip == nil {
		return strings.EqualFold(host, "localhost")
	}
	// Check IPv4 disallowed ranges
	if ip.To4() != nil {
		// Loopback (127.0.0.0/8)
		if strings.HasPrefix(ip.String(), "127.") {
			return true
		}
		// Private (10.0.0.0/8)
		if strings.HasPrefix(ip.String(), "10.") {
			return true
		}
		// Private (172.16.0.0/12)
		if strings.HasPrefix(ip.String(), "172.") {
			secondOctet := ip.To4()[1]
			if secondOctet >= 16 && secondOctet <= 31 {
				return true
			}
		}
		// Private (192.168.0.0/16)
		if strings.HasPrefix(ip.String(), "192.168.") {
			return true
		}
		// Block 0.0.0.0
		if ip.String() == "0.0.0.0" {
			return true
		}
	} else {
		// Check IPv6 disallowed ranges
		switch {
