		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = strings.TrimSpace(n.FirstChild.Data)
		}
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
				attr.Key = strings.ToLower(attr.Key)
				if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
					isDescription = true
				} else if attr.Key == "property" && strings.EqualFold(attr.Val, "og:description") {
					isDescription = true
				} else if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDescription && content != "" {
				description = strings.TrimSpace(content)
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

// checkHostForSSRF checks if a host resolves to a private/loopback IP address with timeout.
func checkHostForSSRF(host string) error {
	// Check if host is an IP address, skip DNS lookup if true
	ip := net.ParseIP(host)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("host is a private IP address: %v", ip)
		}
		return nil // Valid public IP
	}

	// Host is a domain name, perform DNS lookup
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	resolver := net.Resolver{}
	ips, err := resolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("host resolves to private IP address: %v", ip)
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is private or loopback.
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ip.To4() != nil {
		// Private IPv4 ranges
		switch {
		case ip[0] == 10: // 10.0.0.0/8
			return true
		case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31: // 172.16.0.0/12
			return true
		case ip[0] == 192 && ip[1] == 168: // 192.168.0.0/16
			return true
		}
	} else {
		// Private IPv6 ranges (fd00::/8)
		if strings.HasPrefix(ip.String(), "fd") {
			return true
		}
	}
	return false
}

