// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					if strings.EqualFold(attr.Key, "name") {
						name = attr.Val
					} else if strings.EqualFold(attr.Key, "content") {
						content = attr.Val
					} else if strings.EqualFold(attr.Key, "property") {
						// Support OpenGraph description
						if strings.EqualFold(attr.Val, "og:description") {
							name = "description"
						}
					}
				}
				if strings.EqualFold(name, "description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

