			return
		}

		// Limit response body size to prevent DoS (max 1MB)
		const maxBodySize = 1024 * 1024
		var bodyBytes []byte
		if len(res.Body()) > maxBodySize {
			bodyBytes = res.Body()[:maxBodySize]
		} else {
			bodyBytes = res.Body()
		}

		if len(bodyBytes) == 0 {
