// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	// Find title
	var findTitle func(*html.Node)
	findTitle = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
			return
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findTitle(c)
			if title != "" {
				break
			}
		}
	}
	findTitle(doc)

	// Find meta description
	var findDescription func(*html.Node)
	findDescription = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
					name = attr.Val
				}
				if strings.EqualFold(attr.Key, "content") {
					content = attr.Val
				}
			}
			if name != "" && content != "" {
				description = content
				return
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findDescription(c)
			if description != "" {
				break
			}
		}
	}
	findDescription(doc)

	// Trim whitespace from results
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

