	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		sendJSONResponse(ctx, fasthttp.StatusBadRequest, ResponseBody{Error: fmt.Sprintf("Invalid JSON: %v", err)})
