	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(resp.Body()))
	if err != nil {
		sendJSONResponse(ctx, fasthttp.StatusInternalServerError, ResponseBody{Error: fmt.Sprintf("Failed to parse HTML: %v", err)})
		return
	}

	title := doc.Find("title").Text()
	description := ""
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
