func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set CORS headers
	ctx.Response.Header.Set("Access-Control-Allow-Origin", "*")
	ctx.Response.Header.Set("Access-Control-Allow-Methods", "POST, OPTIONS")
	ctx.Response.Header.Set("Access-Control-Allow-Headers", "Content-Type")

	// Handle OPTIONS request for CORS
	if ctx.IsOptions() {
		ctx.SetStatusCode(fasthttp.StatusNoContent)
		return
	}

	// Only handle POST requests
	if string(ctx.Method()) != fasthttp.MethodPost {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse the request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Response.SetBodyString(err.Error())
		return
	}

	// Validate URL is present
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Response.SetBodyString("URL field is required")
		return
	}

	// Create fasthttp client with dual stack dialer
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Prepare request
	var req fasthttp.Request
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	// Fetch URL with redirect handling
	var resp fasthttp.Response
	if err := client.DoRedirects(&req, &resp, 5); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Response.SetBodyString(err.Error())
		return
	}

	// Check response status code
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(resp.StatusCode())
		ctx.Response.SetBodyString(fasthttp.StatusMessage(resp.StatusCode()))
		return
	}

	// Parse HTML
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(resp.Body())))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Response.SetBodyString(err.Error())
		return
	}

	// Extract title and description
	title := doc.Find("title").Text()
	description := ""
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		name, exists := s.Attr("name")
		if exists && strings.ToLower(name) == "description" {
			description, _ = s.Attr("content")
		}
		// Also check for meta tags with property="og:description" for OpenGraph
		prop, exists := s.Attr("property")
		if exists && strings.ToLower(prop) == "og:description" && description == "" {
			description, _ = s.Attr("content")
		}
	})

	// Prepare and send response
	response := PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Response.Header.SetContentType("application/json")
	if err := json.NewEncoder(ctx.Response.BodyWriter()).Encode(response); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Response.SetBodyString(err.Error())
		return
	}
}

func main() {
	// Create a request handler that routes to the appropriate function
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.Response.SetBodyString("Not Found")
		}
	}

	// Start the server
	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatal(err)
	}
}

