func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	var respBody ResponseBody

	// Parse request body
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		respBody.Error = "Failed to parse request body: " + err.Error()
		sendResponse(ctx, fasthttp.StatusBadRequest, respBody)
		return
	}

	if reqBody.URL == "" {
		respBody.Error = "URL field is required"
		sendResponse(ctx, fasthttp.StatusBadRequest, respBody)
		return
	}

	// Create fasthttp client with required configurations
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		MaxConnWaitTimeout:  3 * time.Second,
		ReadTimeout:         3 * time.Second,
		WriteTimeout:        3 * time.Second,
		MaxIdemponentCallAttempts: 0,
	}

