	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Fetch content with redirects
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)
	if err := client.DoRedirects(req, resp, 10); err != nil {
		respBody.Error = "Failed to fetch URL: " + err.Error()
		sendResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		return
	}

	// Check response status
	if resp.StatusCode() != fasthttp.StatusOK {
		respBody.Error = fmt.Sprintf("HTTP request failed with status code: %d", resp.StatusCode())
		sendResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		return
	}

	// Check content type is HTML
	contentType := string(resp.Header.ContentType())
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		respBody.Error = fmt.Sprintf("Unexpected content type: %s", contentType)
		sendResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		return
	}

	// Parse HTML to extract title and description
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(resp.Body())))
	if err != nil {
		respBody.Error = "Failed to parse HTML: " + err.Error()
		sendResponse(ctx, fasthttp.StatusInternalServerError, respBody)
		return
	}

	// Extract title
	respBody.Title = doc.Find("title").First().Text()
	respBody.Title = strings.TrimSpace(respBody.Title)

	// Extract meta description
	respBody.Description = doc.Find("meta[name='description']").First().AttrOr("content", "")
	respBody.Description = strings.TrimSpace(respBody.Description)

	// Also check for meta description with property="og:description" as fallback
	if respBody.Description == "" {
		respBody.Description = doc.Find("meta[property='og:description']").First().AttrOr("content", "")
		respBody.Description = strings.TrimSpace(respBody.Description)
	}

	respBody.URL = reqBody.URL

	sendResponse(ctx, fasthttp.StatusOK, respBody)
