package main

import (
	"encoding/json"
	"log"
	"strings"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

// RequestBody represents the structure of the incoming JSON request
type RequestBody struct {
	URL string `json:"url"`
}

// PreviewResult represents the structure of the outgoing JSON response
type PreviewResult struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type to JSON
	ctx.Response.Header.SetContentType("application/json")

	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		log.Printf("Error parsing request body: %v", err)
		resp := PreviewResult{Error: "Invalid request body"}
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Validate URL
	if reqBody.URL == "" {
		resp := PreviewResult{Error: "URL is required"}
		json.NewEncoder(ctx).Encode(resp)
		return
	}

	// Create fasthttp client with required configurations
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Create request
	var req fasthttp.Request
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")
	req.Header.SetUserAgent("Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")

	// Send request with redirect following
	var resp fasthttp.Response
	if err := client.DoRedirects(&req, &resp, 10); err != nil {
		log.Printf("Error fetching URL: %v", err)
		json.NewEncoder(ctx).Encode(PreviewResult{Error: "Failed to fetch URL"})
		return
	}

	// Check if response is HTML
	contentType := string(resp.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		json.NewEncoder(ctx).Encode(PreviewResult{Error: "URL does not return HTML content"})
		return
	}

	// Parse HTML to extract title and description
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(resp.Body())))
	if err != nil {
		log.Printf("Error parsing HTML: %v", err)
		json.NewEncoder(ctx).Encode(PreviewResult{Error: "Failed to parse HTML"})
		return
	}

	// Extract title
	title := doc.Find("title").Text()

	// Extract meta description
	description := ""
	doc.Find("meta").Each(func(i int, s *goquery.Selection) {
		if name, exists := s.Attr("name"); exists && strings.ToLower(name) == "description" {
			if content, cExists := s.Attr("content"); cExists {
				description = content
			}
		}
		// Also check for og:description for Open Graph
		if property, exists := s.Attr("property"); exists && strings.ToLower(property) == "og:description" {
			if content, cExists := s.Attr("content"); cExists && description == "" {
				description = content
			}
		}
	})

	// Return success response
	json.NewEncoder(ctx).Encode(PreviewResult{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
	// Create a request handler that routes to the appropriate function
	handler := func(ctx *fasthttp.RequestCtx) {
		path := string(ctx.Path())
		if path == "/fetch-preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start the server
	log.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

